        choice_1: 0,
        choice_2: 0,
        low_coder: [[0; LOW_CODER_SYMBOLS]; 1 << NUM_POS_BITS_MAX],
        mid_coder: [[0; MID_CODER_SYMBOLS]; 1 << NUM_POS_BITS_MAX],
