        is_rep: [0; NUM_STATES],
        is_rep_g0: [0; NUM_STATES],
        is_rep_g1: [0; NUM_STATES],
        is_rep_g2: [0; NUM_STATES],
        is_rep0_long: [0; NUM_STATES << NUM_POS_BITS_MAX],
    };
