static void perplexity_encoder_encode_bit(EncoderInterface* enc, bool bit, Prob prob) {
  uint64_t* perplexity = (uint64_t*)enc->private_data;
  *perplexity += LOG2_LOOKUP[bit ? (2048 - prob) : prob];
